local baseActor = require "actor.BaseActor"

ItemActor = class("ItemActor", baseActor)

function ItemActor:ctor(pos, itemId, count, meta)
    local itemConfig = ItemsConfig:getItemsByItemId(itemId)
    if not itemConfig then
        itemConfig = {}
    end
    self.super:ctor(pos, 0, itemConfig.dropActorName or "", itemConfig.name, itemConfig.effectName or "", self)
    self.ItemId = itemId
    self.Count = count
    self.Meta = meta
    self.life = 0
end

function ItemActor:clickedActor(player)
    local armor = ArmorConfig:getArmorValueById(self.ItemId)
    local maxMeta = 0
    if armor ~= nil and armor.multiple > 0 then
        maxMeta = armor.ArmorValue * armor.multiple
    end
    local add = player:addItem(self.ItemId, self.Count, self.Meta, false, maxMeta)
    if add then
        self.Count = nil
        return self:destroyActor()
    else
        HostApi.sendCommonTip(player.rakssid, "bag_full")
    end
    return false
end

function ItemActor:onTick()
    self.life = self.life + 1
    if self.life >= GameConfig.ItemLifeCycle then
        self:destroyActor()
    end
end